import type { MandelbrotWorkerType } from "@/types";

/**
 * ベンチマーク用の固定POI定義
 *
 * 実行時の参考情報として N や地点の特徴を note に書いておくと結果の解釈が楽。
 * 新しいPOIを足すときはこの配列に追加する。
 */
export type BenchPOI = {
  id: string;
  label: string;
  x: string;
  y: string;
  r: string;
  N: number;
  mode: MandelbrotWorkerType;
  note?: string;
};

